import java.util.List;

import org.eclipse.rdf4j.common.annotation.Experimental;

/**
 * Multiplicity-observation lattice used to prove whether one memo route is admissible for an observer.
 * <p>
 * BAG is the strongest semantic contract: a BAG-equivalent route is valid for every observer. SET permits routes
 * that may change multiplicity while preserving membership, and EXISTENCE permits routes that only preserve whether
 * at least one row exists.
 */
@Experimental
public enum SemanticScope {
	BAG(OptimizationGoal.BAG_SEMANTICS),
	SET(OptimizationGoal.SET_SEMANTICS),
	EXISTENCE(OptimizationGoal.EXISTENCE_SEMANTICS);

	private final String externalName;

	SemanticScope(String externalName) {
		this.externalName = externalName;
	}

	public String externalName() {
		return externalName;
	}

	/** Returns whether this route requirement is strong enough for the supplied observer. */
	public boolean isAdmissibleFor(SemanticScope observer) {
		SemanticScope safeObserver = observer == null ? BAG : observer;
		return ordinal() <= safeObserver.ordinal();
	}

	/** Returns the route requirement after both derivation constraints have been applied. */
	public SemanticScope constrainedBy(SemanticScope other) {
		SemanticScope safeOther = other == null ? BAG : other;
		return ordinal() >= safeOther.ordinal() ? this : safeOther;
	}

	/** Returns the least restrictive route proven by either structural derivation. */
	public SemanticScope broadenedWith(SemanticScope other) {
		SemanticScope safeOther = other == null ? BAG : other;
		return ordinal() <= safeOther.ordinal() ? this : safeOther;
	}

	public static SemanticScope fromExternalName(String externalName) {
		String normalized = externalName == null || externalName.isBlank()
				? OptimizationGoal.BAG_SEMANTICS
				: externalName;
		for (SemanticScope scope : values()) {
			if (scope.externalName.equals(normalized)) {
				return scope;
			}
		}
		throw new IllegalArgumentException("Unknown Cascades semantic scope: " + normalized);
	}

	static SemanticScope requirementOf(List<RuleProof> proofs) {
		SemanticScope requirement = BAG;
		if (proofs == null) {
			return requirement;
		}
		for (RuleProof proof : proofs) {
			if (proof != null) {
				requirement = requirement.constrainedBy(fromExternalName(proof.semanticScope()));
			}
		}
		return requirement;
	}
}
